-- Reconstruction SQL: Attach local databases and create views
-- that reconstruct the original tables.

ATTACH DATABASE 'local_1.sqlite' AS "local_1";
ATTACH DATABASE 'local_2.sqlite' AS "local_2";
ATTACH DATABASE 'local_3.sqlite' AS "local_3";

-- Reconstruct Examination from local_2.patient_examination
CREATE VIEW "Examination" AS
SELECT
    "local_2"."patient_examination"."examination_id" AS "ID",
    "local_2"."patient_examination"."exam_date" AS "Examination Date",
    "local_2"."patient_examination"."anticardiolipin_igg" AS "aCL IgG",
    "local_2"."patient_examination"."anticardiolipin_igm" AS "aCL IgM",
    "local_2"."patient_examination"."ana_result" AS "ANA",
    "local_2"."patient_examination"."ana_pattern" AS "ANA Pattern",
    "local_2"."patient_examination"."anticardiolipin_iga" AS "aCL IgA",
    "local_2"."patient_examination"."clinical_diagnosis" AS "Diagnosis",
    "local_2"."patient_examination"."kaolin_clotting_time" AS "KCT",
    "local_2"."patient_examination"."rvv_test" AS "RVVT",
    "local_2"."patient_examination"."lupus_anticoagulant" AS "LAC",
    "local_2"."patient_examination"."reported_symptoms" AS "Symptoms",
    "local_2"."patient_examination"."thrombosis_present" AS "Thrombosis"
FROM "local_2"."patient_examination";

-- Reconstruct Laboratory from vertical split + row partition on a fragment
CREATE VIEW "Laboratory" AS
SELECT t0.[AdmissionId], t0.[ObservationDate], t1.[AspartateAminotransferase], t1.[AlanineAminotransferase], t0.[LactateDehydrogenase], t0.[AlkalinePhosphatase], t0.[TotalProtein], t0.[Albumin], t0.[UricAcid], t0.[UreaNitrogen], t0.[Creatinine], t0.[TotalBilirubin], t0.[TotalCholesterol], t0.[Triglycerides], t0.[CreatinePhosphokinase], t0.[Glucose], t1.[WhiteBloodCellCount], t1.[RedBloodCellCount], t0.[Hemoglobin], t1.[Hematocrit], t1.[PlateletCount], t2.[ProthrombinTime], t0.[ActivatedPartialThromboplastinTime], t0.[Fibrinogen], t2.[PlateletImmuneComplex], t2.[ThrombinAntithrombinComplex], t2.[ThrombinAntithrombinComplexRepeat], t4.[u_prot_text], t0.[ImmunoglobulinG], t0.[ImmunoglobulinA], t0.[ImmunoglobulinM], t0.[CReactiveProtein], t4.[ra_res], t4.[rf_res], t0.[ComplementC3], t0.[ComplementC4], t3.[RnpAntibody], t3.[SmithAntibody], t3.[Sc170Antibody], t3.[SsaAntibody], t3.[SsbAntibody], t3.[CentromereAntibody], t3.[AntiDoubleStrandedDNA], t3.[AntiDoubleStrandedDNATypeII]
