SELECT [LaboratoryAlbuminAbove4Point5OrMissing].[__orig_rowid] AS __orig_rowid, [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[AdmissionId], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[ObservationDate], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[LactateDehydrogenase], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[AlkalinePhosphatase], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[TotalProtein], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[Albumin], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[UricAcid], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[UreaNitrogen], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[Creatinine], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[TotalBilirubin], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[TotalCholesterol], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[Triglycerides], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[CreatinePhosphokinase], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[Glucose], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[Hemoglobin], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[ActivatedPartialThromboplastinTime], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[Fibrinogen], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[ImmunoglobulinG], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[ImmunoglobulinA], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[ImmunoglobulinM], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[CReactiveProtein], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[ComplementC3], [local_1].[LaboratoryAlbuminAbove4Point5OrMissing].[ComplementC4] FROM [local_1].[LaboratoryAlbuminAbove4Point5OrMissing]
UNION
SELECT [LaboratoryAlbuminRange3Point9To4Point2].[__orig_rowid] AS __orig_rowid, [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[AdmissionId], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[ObservationDate], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[LactateDehydrogenase], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[AlkalinePhosphatase], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[TotalProtein], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[Albumin], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[UricAcid], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[UreaNitrogen], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[Creatinine], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[TotalBilirubin], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[TotalCholesterol], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[Triglycerides], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[CreatinePhosphokinase], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[Glucose], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[Hemoglobin], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[ActivatedPartialThromboplastinTime], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[Fibrinogen], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[ImmunoglobulinG], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[ImmunoglobulinA], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[ImmunoglobulinM], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[CReactiveProtein], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[ComplementC3], [local_1].[LaboratoryAlbuminRange3Point9To4Point2].[ComplementC4] FROM [local_1].[LaboratoryAlbuminRange3Point9To4Point2]
UNION
SELECT [LaboratoryAlbuminRange4Point2To4Point5].[__orig_rowid] AS __orig_rowid, [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[AdmissionId], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[ObservationDate], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[LactateDehydrogenase], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[AlkalinePhosphatase], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[TotalProtein], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[Albumin], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[UricAcid], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[UreaNitrogen], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[Creatinine], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[TotalBilirubin], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[TotalCholesterol], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[Triglycerides], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[CreatinePhosphokinase], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[Glucose], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[Hemoglobin], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[ActivatedPartialThromboplastinTime], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[Fibrinogen], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[ImmunoglobulinG], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[ImmunoglobulinA], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[ImmunoglobulinM], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[CReactiveProtein], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[ComplementC3], [local_1].[LaboratoryAlbuminRange4Point2To4Point5].[ComplementC4] FROM [local_1].[LaboratoryAlbuminRange4Point2To4Point5]
UNION
SELECT [lab_alb_lte_3_9].[__orig_rowid] AS __orig_rowid, [local_3].[lab_alb_lte_3_9].[admit_id], [local_3].[lab_alb_lte_3_9].[lab_date], [local_3].[lab_alb_lte_3_9].[ldh_val], [local_3].[lab_alb_lte_3_9].[alp_val], [local_3].[lab_alb_lte_3_9].[tp_val], [local_3].[lab_alb_lte_3_9].[alb_val], [local_3].[lab_alb_lte_3_9].[ua_val], [local_3].[lab_alb_lte_3_9].[urea_n_val], [local_3].[lab_alb_lte_3_9].[cre_val], [local_3].[lab_alb_lte_3_9].[tbil_val], [local_3].[lab_alb_lte_3_9].[tcho_val], [local_3].[lab_alb_lte_3_9].[tg_val], [local_3].[lab_alb_lte_3_9].[cpk_val], [local_3].[lab_alb_lte_3_9].[glu_val], [local_3].[lab_alb_lte_3_9].[hgb_val], [local_3].[lab_alb_lte_3_9].[aptt_val], [local_3].[lab_alb_lte_3_9].[fg_val], [local_3].[lab_alb_lte_3_9].[igg_val], [local_3].[lab_alb_lte_3_9].[iga_val], [local_3].[lab_alb_lte_3_9].[igm_val], [local_3].[lab_alb_lte_3_9].[crp_text], [local_3].[lab_alb_lte_3_9].[c3_val], [local_3].[lab_alb_lte_3_9].[c4_val] FROM [local_3].[lab_alb_lte_3_9]
) t0
JOIN [local_1].[LaboratoryAlbuminSecondary] t1 ON t0.[__orig_rowid] = t1.[__orig_rowid]
JOIN [local_1].[LaboratoryCoagulationAppttPanel] t2 ON t0.[__orig_rowid] = t2.[__orig_rowid]
JOIN [local_1].[LaboratoryCentromereAutoantibodyPanel] t3 ON t0.[__orig_rowid] = t3.[__orig_rowid]
JOIN [local_3].[lab_ra_serology] t4 ON t0.[__orig_rowid] = t4.[__orig_rowid];

-- Reconstruct Patient from vertical split + row partition on a fragment
CREATE VIEW "Patient" AS
SELECT t0.[AdmissionId], t0.[Gender], t1.[DateOfBirth], t0.[RecordDate], t1.[FirstVisitDate], t0.[AdmissionType], t0.[PrimaryDiagnosis]
FROM [local_1].[PatientAdmissionRecord] t0
JOIN (
SELECT [PatientAdmissionAfter1997Aug20].[__orig_rowid] AS __orig_rowid, [local_1].[PatientAdmissionAfter1997Aug20].[AdmissionId], [local_1].[PatientAdmissionAfter1997Aug20].[DateOfBirth], [local_1].[PatientAdmissionAfter1997Aug20].[RecordDate], [local_1].[PatientAdmissionAfter1997Aug20].[FirstVisitDate], [local_1].[PatientAdmissionAfter1997Aug20].[AdmissionType], [local_1].[PatientAdmissionAfter1997Aug20].[PrimaryDiagnosis] FROM [local_1].[PatientAdmissionAfter1997Aug20]
UNION
SELECT [PatientAdmissionBefore1994Feb22].[__orig_rowid] AS __orig_rowid, [local_1].[PatientAdmissionBefore1994Feb22].[AdmissionId], [local_1].[PatientAdmissionBefore1994Feb22].[DateOfBirth], [local_1].[PatientAdmissionBefore1994Feb22].[RecordDate], [local_1].[PatientAdmissionBefore1994Feb22].[FirstVisitDate], [local_1].[PatientAdmissionBefore1994Feb22].[AdmissionType], [local_1].[PatientAdmissionBefore1994Feb22].[PrimaryDiagnosis] FROM [local_1].[PatientAdmissionBefore1994Feb22]
UNION
SELECT [admit_desc_gt_1994_02_22_to_1997_03_01].[__orig_rowid] AS __orig_rowid, [local_3].[admit_desc_gt_1994_02_22_to_1997_03_01].[admit_id], [local_3].[admit_desc_gt_1994_02_22_to_1997_03_01].[birth_date], [local_3].[admit_desc_gt_1994_02_22_to_1997_03_01].[desc_date], [local_3].[admit_desc_gt_1994_02_22_to_1997_03_01].[visit_date], [local_3].[admit_desc_gt_1994_02_22_to_1997_03_01].[admit_mode], [local_3].[admit_desc_gt_1994_02_22_to_1997_03_01].[diag_text] FROM [local_3].[admit_desc_gt_1994_02_22_to_1997_03_01]
UNION
SELECT [admit_desc_gt_1997_03_01_to_1997_08_20].[__orig_rowid] AS __orig_rowid, [local_3].[admit_desc_gt_1997_03_01_to_1997_08_20].[admit_id], [local_3].[admit_desc_gt_1997_03_01_to_1997_08_20].[birth_date], [local_3].[admit_desc_gt_1997_03_01_to_1997_08_20].[desc_date], [local_3].[admit_desc_gt_1997_03_01_to_1997_08_20].[visit_date], [local_3].[admit_desc_gt_1997_03_01_to_1997_08_20].[admit_mode], [local_3].[admit_desc_gt_1997_03_01_to_1997_08_20].[diag_text] FROM [local_3].[admit_desc_gt_1997_03_01_to_1997_08_20]
) t1 ON t0.[__orig_rowid] = t1.[__orig_rowid];
